import{_ as a,c as t,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"z.ai: 集成边界 | Antigravity Manager","description":"了解 Antigravity Manager 中 z.ai 的集成边界。掌握哪些请求通过 z.ai（仅 Claude 协议）、dispatch_mode 路由规则、模型映射方法、头部安全策略，以及 MCP 反向代理和 Vision MCP 的限制。","frontmatter":{"title":"z.ai: 集成边界 | Antigravity Manager","sidebarTitle":"z.ai 边界","subtitle":"z.ai 集成边界（已实现 vs 明确未实现）","description":"了解 Antigravity Manager 中 z.ai 的集成边界。掌握哪些请求通过 z.ai（仅 Claude 协议）、dispatch_mode 路由规则、模型映射方法、头部安全策略，以及 MCP 反向代理和 Vision MCP 的限制。","tags":["z.ai","MCP","Claude","Integration Boundaries"],"prerequisite":["start-getting-started","platforms-mcp"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),i={name:"lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function n(l,e,d,s,c,p){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="z-ai-integration-boundaries-implemented-vs-explicitly-unimplemented" tabindex="-1">z.ai Integration Boundaries (Implemented vs Explicitly Unimplemented) <a class="header-anchor" href="#z-ai-integration-boundaries-implemented-vs-explicitly-unimplemented" aria-label="Permalink to &quot;z.ai Integration Boundaries (Implemented vs Explicitly Unimplemented)&quot;">​</a></h1><p>This document focuses on the <strong>boundaries</strong> of z.ai integration in Antigravity Tools, not &quot;how to integrate it.&quot; If you find a feature isn&#39;t working, check here first: is it unconfigured, or simply not implemented?</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Determine whether you should expect z.ai for a task: what&#39;s &quot;implemented&quot; vs &quot;explicitly not done&quot;</li><li>Understand which endpoints z.ai affects (and which are completely unaffected)</li><li>See source code/documentation evidence for each conclusion (with GitHub line number links) for your own verification</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>You may have already enabled z.ai in Antigravity Tools, but you&#39;re encountering these uncertainties:</p><ul><li>Why do some requests go through z.ai while others don&#39;t at all?</li><li>Can the MCP endpoints serve as a &quot;complete MCP Server&quot;?</li><li>Do the visible switches in the UI actually correspond to real implementations?</li></ul><h2 id="what-is-z-ai-integration-in-this-project" tabindex="-1">What Is z.ai Integration (In This Project)? <a class="header-anchor" href="#what-is-z-ai-integration-in-this-project" aria-label="Permalink to &quot;What Is z.ai Integration (In This Project)?&quot;">​</a></h2><p><strong>z.ai integration</strong> in Antigravity Tools is an optional &quot;upstream provider + MCP extension.&quot; It only takes over Claude protocol requests under specific conditions, and provides MCP Search/Reader reverse proxy plus a minimal Vision MCP built-in server; it&#39;s not a full-protocol, full-capability replacement solution.</p><div class="info custom-block"><p class="custom-block-title">One-Sentence Memory</p><p>Think of z.ai as &quot;an optional upstream for Claude requests + a set of toggleable MCP endpoints,&quot; not &quot;bringing all of z.ai&#39;s capabilities over completely.&quot;</p></div><h2 id="implemented-stable-and-available-source-code-as-truth" tabindex="-1">Implemented: Stable and Available (Source Code as Truth) <a class="header-anchor" href="#implemented-stable-and-available-source-code-as-truth" aria-label="Permalink to &quot;Implemented: Stable and Available (Source Code as Truth)&quot;">​</a></h2><h3 id="_1-only-claude-protocol-goes-through-z-ai-v1-messages-v1-messages-count-tokens" tabindex="-1">1) Only Claude Protocol Goes Through z.ai (/v1/messages + /v1/messages/count_tokens) <a class="header-anchor" href="#_1-only-claude-protocol-goes-through-z-ai-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) Only Claude Protocol Goes Through z.ai (/v1/messages + /v1/messages/count_tokens)&quot;">​</a></h3><p>z.ai&#39;s Anthropic upstream forwarding only happens in the z.ai branch of the Claude handler:</p><ul><li><code>POST /v1/messages</code>: When <code>use_zai=true</code>, calls <code>forward_anthropic_json(...)</code> to forward the JSON request to z.ai&#39;s Anthropic-compatible endpoint</li><li><code>POST /v1/messages/count_tokens</code>: Also forwards when z.ai is enabled; otherwise returns a placeholder <code>{input_tokens:0, output_tokens:0}</code></li></ul><p>Evidence:</p><ul><li>z.ai branch selection and forwarding entry point: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>z.ai branch and placeholder return for count_tokens: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>z.ai Anthropic forwarding implementation: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">How to Understand &quot;Streaming Response&quot;</p><p><code>forward_anthropic_json</code> streams the upstream response body back to the client using <code>bytes_stream()</code>, without parsing SSE (see Response body construction in <code>providers/zai_anthropic.rs</code>).</p></div><h3 id="_2-the-real-meaning-of-dispatch-mode-dispatch-mode" tabindex="-1">2) The &quot;Real Meaning&quot; of Dispatch Mode (dispatch_mode) <a class="header-anchor" href="#_2-the-real-meaning-of-dispatch-mode-dispatch-mode" aria-label="Permalink to &quot;2) The &quot;Real Meaning&quot; of Dispatch Mode (dispatch_mode)&quot;">​</a></h3><p><code>dispatch_mode</code> determines whether <code>/v1/messages</code> goes through z.ai:</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>What Happens</th><th>Evidence</th></tr></thead><tbody><tr><td><code>off</code></td><td>Never use z.ai</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>All Claude requests go through z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Only go through z.ai when Google pool is unavailable (0 accounts or &quot;no available accounts&quot;)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>Treat z.ai as an &quot;additional slot&quot; participating in round-robin (no guaranteed hit)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Common Misconception About pooled</p><p><code>pooled</code> doesn&#39;t mean &quot;use both z.ai and Google account pools together, and split traffic by weight.&quot; The code explicitly states &quot;no strict guarantees&quot; – it&#39;s essentially a round-robin slot (z.ai only used when <code>slot == 0</code>).</p></div><h3 id="_3-model-mapping-how-claude-model-names-become-z-ai-s-glm" tabindex="-1">3) Model Mapping: How Claude Model Names Become z.ai&#39;s glm-*? <a class="header-anchor" href="#_3-model-mapping-how-claude-model-names-become-z-ai-s-glm" aria-label="Permalink to &quot;3) Model Mapping: How Claude Model Names Become z.ai&#39;s glm-*?&quot;">​</a></h3><p>Before forwarding to z.ai, if the request body contains a <code>model</code> field, it gets rewritten:</p><ol><li>Exact match in <code>proxy.zai.model_mapping</code> (supports both original string and lower-case key)</li><li><code>zai:&lt;model&gt;</code> prefix: Remove <code>zai:</code> and use directly</li><li><code>glm-*</code>: Keep unchanged</li><li>Non-<code>claude-*</code>: Keep unchanged</li><li><code>claude-*</code> and contains <code>opus/haiku</code>: Map to <code>proxy.zai.models.opus/haiku</code>; otherwise default to <code>sonnet</code></li></ol><p>Evidence: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-header-security-policy-during-forwarding-avoid-leaking-local-proxy-key" tabindex="-1">4) Header Security Policy During Forwarding (Avoid Leaking Local Proxy Key) <a class="header-anchor" href="#_4-header-security-policy-during-forwarding-avoid-leaking-local-proxy-key" aria-label="Permalink to &quot;4) Header Security Policy During Forwarding (Avoid Leaking Local Proxy Key)&quot;">​</a></h3><p>z.ai upstream forwarding doesn&#39;t &quot;pass all Headers as-is,&quot; but applies two layers of defense:</p><ul><li>Only allows a small subset of Headers (e.g., <code>content-type</code>, <code>accept</code>, <code>anthropic-version</code>, <code>user-agent</code>)</li><li>Injects z.ai&#39;s API Key into upstream (prioritizes keeping the client&#39;s auth method: <code>x-api-key</code> or <code>Authorization: Bearer ...</code>)</li></ul><p>Evidence:</p><ul><li>Header whitelist: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>Inject z.ai auth: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="implemented-mcp-search-reader-reverse-proxy-vision-built-in" tabindex="-1">Implemented: MCP (Search/Reader Reverse Proxy + Vision Built-in) <a class="header-anchor" href="#implemented-mcp-search-reader-reverse-proxy-vision-built-in" aria-label="Permalink to &quot;Implemented: MCP (Search/Reader Reverse Proxy + Vision Built-in)&quot;">​</a></h2><h3 id="_1-mcp-search-reader-reverse-proxy-to-z-ai-s-mcp-endpoints" tabindex="-1">1) MCP Search/Reader: Reverse Proxy to z.ai&#39;s MCP Endpoints <a class="header-anchor" href="#_1-mcp-search-reader-reverse-proxy-to-z-ai-s-mcp-endpoints" aria-label="Permalink to &quot;1) MCP Search/Reader: Reverse Proxy to z.ai&#39;s MCP Endpoints&quot;">​</a></h3><p>Local endpoints and upstream addresses are hardcoded:</p><table tabindex="0"><thead><tr><th>Local Endpoint</th><th>Upstream Address</th><th>Switch</th><th>Evidence</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 Is Not a &quot;Network Problem&quot;</p><p>As long as <code>proxy.zai.mcp.enabled=false</code>, or the corresponding <code>web_search_enabled/web_reader_enabled=false</code>, these endpoints will directly return 404.</p></div><p>Evidence:</p><ul><li>MCP master switch and z.ai key validation: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Route registration: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-a-minimal-streamable-http-mcp-built-in-server" tabindex="-1">2) Vision MCP: A &quot;Minimal Streamable HTTP MCP&quot; Built-in Server <a class="header-anchor" href="#_2-vision-mcp-a-minimal-streamable-http-mcp-built-in-server" aria-label="Permalink to &quot;2) Vision MCP: A &quot;Minimal Streamable HTTP MCP&quot; Built-in Server&quot;">​</a></h3><p>Vision MCP is not a reverse proxy; it&#39;s a local built-in implementation:</p><ul><li>Endpoint: <code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> supports: <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code></li><li><code>GET</code> returns SSE keepalive (requires initialized session)</li><li><code>DELETE</code> ends session</li></ul><p>Evidence:</p><ul><li>Handler main entry and method dispatch: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Implementation of <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code>: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Vision MCP&#39;s &quot;minimal implementation&quot; positioning: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-vision-mcp-tool-set-8-tools-and-file-size-limits" tabindex="-1">3) Vision MCP Tool Set (8 Tools) and File Size Limits <a class="header-anchor" href="#_3-vision-mcp-tool-set-8-tools-and-file-size-limits" aria-label="Permalink to &quot;3) Vision MCP Tool Set (8 Tools) and File Size Limits&quot;">​</a></h3><p>Tool list comes from <code>tool_specs()</code>:</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>Evidence: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>Local files are read and encoded as <code>data:&lt;mime&gt;;base64,...</code>, with hard limits:</p><ul><li>Image max size: 5 MB (<code>image_source_to_content(..., 5)</code>)</li><li>Video max size: 8 MB (<code>video_source_to_content(..., 8)</code>)</li></ul><p>Evidence: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="explicitly-unimplemented-don-t-expect-based-on-documentation-statements-and-implementation-details" tabindex="-1">Explicitly Unimplemented / Don&#39;t Expect (Based on Documentation Statements and Implementation Details) <a class="header-anchor" href="#explicitly-unimplemented-don-t-expect-based-on-documentation-statements-and-implementation-details" aria-label="Permalink to &quot;Explicitly Unimplemented / Don&#39;t Expect (Based on Documentation Statements and Implementation Details)&quot;">​</a></h2><h3 id="_1-z-ai-usage-budget-monitoring-usage-budget-not-implemented" tabindex="-1">1) z.ai Usage/Budget Monitoring (usage/budget) Not Implemented <a class="header-anchor" href="#_1-z-ai-usage-budget-monitoring-usage-budget-not-implemented" aria-label="Permalink to &quot;1) z.ai Usage/Budget Monitoring (usage/budget) Not Implemented&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> explicitly states &quot;not implemented yet.&quot; This means:</p><ul><li>You cannot expect Antigravity Tools to provide z.ai usage/budget queries or alerts</li><li>Quota Protection won&#39;t automatically read z.ai&#39;s budget/usage data</li></ul><p>Evidence: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-is-not-a-complete-mcp-server" tabindex="-1">2) Vision MCP Is Not a Complete MCP Server <a class="header-anchor" href="#_2-vision-mcp-is-not-a-complete-mcp-server" aria-label="Permalink to &quot;2) Vision MCP Is Not a Complete MCP Server&quot;">​</a></h3><p>Vision MCP is currently positioned as a minimal implementation that&#39;s &quot;just enough for tool calls&quot;: prompts/resources, resumability, streamed tool output, etc. are not implemented yet.</p><p>Evidence: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-won-t-reflect-z-ai-s-real-model-list" tabindex="-1">3) <code>/v1/models/claude</code> Won&#39;t Reflect z.ai&#39;s Real Model List <a class="header-anchor" href="#_3-v1-models-claude-won-t-reflect-z-ai-s-real-model-list" aria-label="Permalink to &quot;3) `/v1/models/claude` Won&#39;t Reflect z.ai&#39;s Real Model List&quot;">​</a></h3><p>The model list returned by this endpoint comes from local built-in mapping and custom mapping (<code>get_all_dynamic_models</code>), and won&#39;t request z.ai upstream&#39;s <code>/v1/models</code>.</p><p>Evidence:</p><ul><li>handler: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>List generation logic: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="configuration-field-quick-reference-z-ai-related" tabindex="-1">Configuration Field Quick Reference (z.ai Related) <a class="header-anchor" href="#configuration-field-quick-reference-z-ai-related" aria-label="Permalink to &quot;Configuration Field Quick Reference (z.ai Related)&quot;">​</a></h2><p>z.ai configuration is under <code>ProxyConfig.zai</code>, including these fields:</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code> (<code>off/exclusive/pooled/fallback</code>)</li><li><code>model_mapping</code> (exact match override)</li><li><code>models.{opus,sonnet,haiku}</code> (Claude family default mapping)</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>Default values (base_url / default models) are also in the same file:</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>Evidence: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>z.ai currently only takes over Claude protocol (<code>/v1/messages</code> + <code>count_tokens</code>); other protocol endpoints don&#39;t &quot;automatically go through z.ai&quot;</li><li>MCP Search/Reader are reverse proxies; Vision MCP is a local minimal implementation, not a complete MCP Server</li><li>The model list in <code>/v1/models/claude</code> comes from local mapping and doesn&#39;t represent z.ai upstream&#39;s real models</li></ul><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../changelog/release-notes/">Version Evolution</a></strong>.</p></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>z.ai integration scope (Claude protocol + MCP + Vision MCP)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>z.ai dispatch mode and model defaults</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>z.ai default base_url / default models</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td><code>/v1/messages</code> routing logic (whether to go through z.ai)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td><code>/v1/messages/count_tokens</code> z.ai forwarding and placeholder return</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>z.ai Anthropic upstream forwarding (JSON forwarding + response streaming)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>z.ai model mapping rules (map_model_for_zai)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>Header whitelist + inject z.ai auth</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>70-110</td></tr><tr><td>MCP Search/Reader reverse proxy and switches</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Vision MCP minimal implementation positioning (not full MCP Server)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Vision tools list and limits (tool_specs + file size + stream=false)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td><code>/v1/models/claude</code> model list source (local mapping, not upstream query)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>Usage/budget monitoring not implemented (documentation statement)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',76)])])}const h=a(i,[["render",n]]);export{m as __pageData,h as default};
